@dataclasses.dataclass
class Record(object):
    id: int
    md5sum: str
    ref: int
    data: bool
    embed: bool
    createtime: float
    visittime: float
    token_id: int
    token_num: int
    mem_block: MemoryBlock

    def __hash__(self) -> int:
